import ArrowBackIosNewRoundedIcon from '@mui/icons-material/ArrowBackIosNewRounded';
import ArrowForwardIosRoundedIcon from '@mui/icons-material/ArrowForwardIosRounded';
import { Box, IconButton, Typography, Stack } from "@mui/material";
import { useState } from "react";
import { useNavigate } from "react-router-dom";

const Mypagination = (props) => {
    const { page, value, allpages } = props;
    const [currentPage, setCurrentPage] = useState(page);
    const navigate = useNavigate();

    let custompagination = [];
    const pushToCustomPagination = (i) => {
        return (
            custompagination.push(
                <IconButton 
                    variant="contained" 
                    size="small"
                    sx={{
                        backgroundColor: i === currentPage ? "primary.main" : "transparent",
                        color: i === currentPage ? "black" : "white",
                        mx: 0.5,
                        borderRadius: '12px',
                        width: '40px',
                        height: '40px',
                        fontSize: '0.875rem',
                        fontWeight: 700,
                        border: '1px solid',
                        borderColor: i === currentPage ? 'primary.main' : 'rgba(255,255,255,0.1)',
                        '&:hover': { 
                            backgroundColor: i === currentPage ? 'primary.main' : 'rgba(255,255,255,0.05)',
                            borderColor: 'primary.main',
                            color: i === currentPage ? 'black' : 'primary.main',
                        },
                    }}
                    href={i === 1 ? (value ? "/" + value + "/page1" : "/") : ((value ? "/" + value + "/" : '') + 'page' + i)}
                    key={i}
                >
                    {i}
                </IconButton>
            )
        )
    }

    if (allpages > 6) {
        if (currentPage <= 3) {
            for (let i = 1; i < 5; i++) pushToCustomPagination(i);
            custompagination.push(<Typography key="dots1" sx={{ px: 1, opacity: 0.5 }}>...</Typography>)
            pushToCustomPagination(allpages);
        } else if (currentPage < allpages - 2) {
            pushToCustomPagination(1);
            custompagination.push(<Typography key="dots1" sx={{ px: 1, opacity: 0.5 }}>...</Typography>)
            pushToCustomPagination(currentPage - 1);
            pushToCustomPagination(currentPage);
            pushToCustomPagination(currentPage + 1);
            custompagination.push(<Typography key="dots2" sx={{ px: 1, opacity: 0.5 }}>...</Typography>)
            pushToCustomPagination(allpages);
        } else {
            pushToCustomPagination(1);
            custompagination.push(<Typography key="dots1" sx={{ px: 1, opacity: 0.5 }}>...</Typography>)
            for (let i = allpages - 3; i <= allpages; i++) pushToCustomPagination(i);
        }
    } else {
        for (let i = 1; i <= allpages; i++) pushToCustomPagination(i);
    }

    if (custompagination.length > 1) {
        return (
            <Stack 
                direction="row" 
                spacing={1} 
                alignItems="center" 
                justifyContent="center" 
                sx={{ mt: 8, mb: 12 }}
            >
                <IconButton
                    disabled={currentPage === 1}
                    sx={{ 
                        color: 'white', 
                        opacity: currentPage === 1 ? 0.3 : 1,
                        '&:hover': { color: 'primary.main' }
                    }}
                    onClick={() => {
                        const prevPage = currentPage - 1;
                        setCurrentPage(prevPage);
                        navigate(prevPage === 1 ? '/' : '/' + (value ? value + "/" : '') + 'page' + prevPage);
                        window.scrollTo(0, 0);
                    }}
                >
                    <ArrowBackIosNewRoundedIcon fontSize="small" />
                </IconButton>

                {custompagination}

                <IconButton
                    disabled={currentPage === allpages}
                    sx={{ 
                        color: 'white', 
                        opacity: currentPage === allpages ? 0.3 : 1,
                        '&:hover': { color: 'primary.main' }
                    }}
                    onClick={() => {
                        const nextPage = currentPage + 1;
                        setCurrentPage(nextPage);
                        navigate('/' + (value ? value + "/" : '') + 'page' + nextPage);
                        window.scrollTo(0, 0);
                    }}
                >
                    <ArrowForwardIosRoundedIcon fontSize="small" />
                </IconButton>
            </Stack>
        );
    } else {
        return (
            <Box sx={{ py: 8, textAlign: 'center', opacity: 0.6 }}>
                <Typography variant="body1">That's everything we have for you today.</Typography>
            </Box>
        )
    }
};

export default Mypagination;
